class CardDetails {
  final String _tokenizedNumber;
  final String _tokenizedExpiry;
  final String _tokenizedCvv;
  final String cardholderName;
  final String? billingZip;

  CardDetails._({
    required String tokenizedNumber,
    required String tokenizedExpiry,
    required String tokenizedCvv,
    required this.cardholderName,
    this.billingZip,
  })  : _tokenizedNumber = tokenizedNumber,
        _tokenizedExpiry = tokenizedExpiry,
        _tokenizedCvv = tokenizedCvv;

  factory CardDetails.create({
    required String cardNumber,
    required String expiry,
    required String cvv,
    required String cardholderName,
    String? billingZip,
  }) {
    // Validate before tokenizing
    if (!CardValidator.isValidCardNumber(cardNumber)) {
      throw PaymentException('Invalid card number', code: 'INVALID_CARD');
    }
    if (!CardValidator.isValidExpiry(expiry)) {
      throw PaymentException('Invalid expiry date', code: 'INVALID_EXPIRY');
    }
    if (!CardValidator.isValidCvv(cvv)) {
      throw PaymentException('Invalid CVV', code: 'INVALID_CVV');
    }

    return CardDetails._(
      tokenizedNumber: PCITokenizer.tokenize(cardNumber),
      tokenizedExpiry: PCITokenizer.tokenize(expiry),
      tokenizedCvv: PCITokenizer.tokenize(cvv),
      cardholderName: cardholderName,
      billingZip: billingZip,
    );
  }

  String get maskedNumber {
    final decoded = PCITokenizer.detokenize(_tokenizedNumber);
    final cleaned = decoded.replaceAll(RegExp(r'\s'), '');
    return '**** **** **** ${cleaned.substring(cleaned.length - 4)}';
  }

  String get token => _tokenizedNumber;
  String get expiryToken => _tokenizedExpiry;
  String get cvvToken => _tokenizedCvv;
}

