class PCITokenizer {
  static final _key = utf8.encode('payment_module_secret_key_replace_in_prod');

  static String tokenize(String sensitiveData) {
    final bytes = utf8.encode(sensitiveData);
    final hmacSha256 = Hmac(sha256, _key);
    final digest = hmacSha256.convert(bytes);

    // In production, this would call a secure tokenization vault
    // For now, we use base64 encoding with HMAC signature
    final payload = base64Encode(bytes);
    return '$payload.${digest.toString().substring(0, 16)}';
  }

  static String detokenize(String token) {
    final parts = token.split('.');
    if (parts.length != 2) {
      throw PaymentException('Invalid token format', code: 'TOKEN_ERROR');
    }

    final decoded = base64Decode(parts[0]);
    final data = utf8.decode(decoded);

    // Verify integrity
    final bytes = utf8.encode(data);
    final hmacSha256 = Hmac(sha256, _key);
    final digest = hmacSha256.convert(bytes);
    final expectedSig = digest.toString().substring(0, 16);

    if (parts[1] != expectedSig) {
      throw PaymentException('Token integrity check failed', code: 'TOKEN_TAMPERED');
    }

    return data;
  }
}

class CardValidator {
  static bool isValidCardNumber(String number) {
    final cleaned = number.replaceAll(RegExp(r'\s|-'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;
    if (!RegExp(r'^\d+$').hasMatch(cleaned)) return false;
    return _luhnCheck(cleaned);
  }

  static bool _luhnCheck(String number) {
    int sum = 0;
    bool alternate = false;
    for (int i = number.length - 1; i >= 0; i--) {
      int digit = int.parse(number[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  static bool isValidExpiry(String expiry) {
    final parts = expiry.split('/');
    if (parts.length != 2) return false;

    final month = int.tryParse(parts[0]);
    final year = int.tryParse(parts[1]);
    if (month == null || year == null) return false;
    if (month < 1 || month > 12) return false;

    final now = DateTime.now();
    final fullYear = year < 100 ? 2000 + year : year;
    final expiryDate = DateTime(fullYear, month + 1, 0);

    return expiryDate.isAfter(now);
  }

  static bool isValidCvv(String cvv) {
    return RegExp(r'^\d{3,4}$').hasMatch(cvv);
  }

  static String getCardBrand(String number) {
    final cleaned = number.replaceAll(RegExp(r'\s|-'), '');
    if (cleaned.startsWith('4')) return 'Visa';
    if (RegExp(r'^5[1-5]').hasMatch(cleaned)) return 'Mastercard';
    if (RegExp(r'^3[47]').hasMatch(cleaned)) return 'Amex';
    if (RegExp(r'^6(?:011|5)').hasMatch(cleaned)) return 'Discover';
    if (RegExp(r'^35(?:2[89]|[3-8])').hasMatch(cleaned)) return 'JCB';
    return 'Unknown';
  }
}

class SecurityManager {
  static final SecurityManager _instance = SecurityManager._();
  factory SecurityManager() => _instance;
  SecurityManager._();

  final List<String> _auditLog = [];
  bool _isInitialized = false;

  void initialize() {
    _isInitialized = true;
    _log('SecurityManager initialized');
  }

  void _log(String event) {
    final entry = '${DateTime.now().toIso8601String()} | $event';
    _auditLog.add(entry);
    if (kDebugMode) {
      print('[SECURITY] $event');
    }
  }

  void logTransaction(String transactionId, String action) {
    _log('Transaction $transactionId: $action');
  }

  void logSecurityEvent(String event, {Map<String, dynamic>? details}) {
    _log('SECURITY_EVENT: $event ${details != null ? json.encode(details) : ''}');
  }

  List<String> getAuditLog() => List.unmodifiable(_auditLog);

  String generateIdempotencyKey(String orderId) {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final data = '$orderId-$timestamp';
    return sha256.convert(utf8.encode(data)).toString().substring(0, 32);
  }

  bool validateWebhookSignature(String payload, String signature, String secret) {
    final hmac = Hmac(sha256, utf8.encode(secret));
    final expectedSignature = hmac.convert(utf8.encode(payload)).toString();
    return signature == expectedSignature;
  }
}

